#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAXN 210

int main ()
{
    static char data[MAXN];
    static int a[MAXN][MAXN];
    memset(a,0,sizeof(a));
    scanf("%s",data);
    int N = strlen(data);
    int x = 105;
    int y = 105;
    a[x][y] = 1;
    int i;
    for (i = 2; i <= (N+1); i++)
    {
        int nx = x;
        int ny = y;
        if (data[i-2] == 'L') nx--;
        else if (data[i-2] == 'R') nx++;
        else if (data[i-2] == 'U') ny++;
        else ny--;

        if ((a[nx-1][ny] > 0) && (a[nx-1][ny] < (i-1)))
        {
            printf("BUG\n");
            return 0;
        }
        if ((a[nx+1][ny] > 0) && (a[nx+1][ny] < (i-1)))
        {
            printf("BUG\n");
            return 0;
        }
        if ((a[nx][ny-1] > 0) && (a[nx][ny-1] < (i-1)))
        {
            printf("BUG\n");
            return 0;
        }
        if ((a[nx][ny+1] > 0) && (a[nx][ny+1] < (i-1)))
        {
            printf("BUG\n");
            return 0;
        }
        if (a[nx][ny] > 0)
        {
            printf("BUG\n");
            return 0;
        }        

        a[nx][ny] = i;
        x = nx;
        y = ny;
    }
    printf("OK\n");
    return 0;
}

