use std::io::{self, BufRead};
use std::collections::HashSet;

fn parse_problem<B: BufRead>(mut input: B) -> io::Result<Vec<(i64, i64)>> {
    let mut buffer = String::new();
    input.read_line(&mut buffer)?;
    buffer.truncate(buffer.trim_end().len());
    let mut positions = Vec::new();
    let mut curr = (0, 0);
    for c in buffer.chars() {
        let next = match c {
            'L' => Ok((curr.0 - 1, curr.1)),
            'U' => Ok((curr.0, curr.1 + 1)),
            'R' => Ok((curr.0 + 1, curr.1)),
            'D' => Ok((curr.0, curr.1 - 1)),
            _ => Err(io::Error::new(io::ErrorKind::InvalidInput, "bad input")),
        }?;
        positions.push(curr);
        curr = next;
    }
    positions.push(curr);
    Ok(positions)
}

fn main() -> io::Result<()> {
    let positions = parse_problem(io::stdin().lock())?;
    let mut seen_positions = HashSet::new();
    let mut last_position = (0, 0);
    for pos in positions.iter().skip(1) {
        if !seen_positions.insert(*pos) {
            println!("BUG");
            return Ok(())
        }
        seen_positions.insert((last_position.0 + 1, last_position.1));
        seen_positions.insert((last_position.0 - 1, last_position.1));
        seen_positions.insert((last_position.0, last_position.1 + 1));
        seen_positions.insert((last_position.0, last_position.1 - 1));
        last_position = *pos;
    }
    println!("OK");
    Ok(())
}
